node -e "
const schema = require('./schema.json');
const task = require('./task.json');
const Ajv = require('ajv');

try {
  const ajv = new Ajv();
  const validate = ajv.compile(schema);
  const valid = validate(task);

  if (valid) {
    console.log('✓ task.json is VALID against schema.json');
    console.log('');
    console.log('Validation Details:');
    console.log('- Fields present:', Object.keys(task).length);
    console.log('- Fields:', Object.keys(task).join(', '));
    console.log('- Required fields check: title ✓, priority ✓');
    console.log('- No optional fields added: tags ✗, assignee ✗');
    console.log('- Additional properties: none ✓');
  } else {
    console.log('✗ VALIDATION FAILED');
    console.log('Errors:', validate.errors);
  }
} catch (e) {
  // If ajv not available, do basic validation
  console.log('Basic validation:');
  console.log('- Has title:', !!task.title);
  console.log('- Has priority:', !!task.priority, '(value:', task.priority, ')');
  console.log('- Has due_date:', !!task.due_date);
  console.log('- Field count:', Object.keys(task).length);
  console.log('- Keys:', Object.keys(task).join(', '));
  console.log('- Matches enum [low, medium, high, critical]:', ['low', 'medium', 'high', 'critical'].includes(task.priority));
  console.log('- Date format YYYY-MM-DD:', /^[0-9]{4}-[0-9]{2}-[0-9]{2}$/.test(task.due_date));
}
"

node -e "
const schema = require('./schema.json');
const task = require('./task.json');

console.log('=== VALIDATION REPORT ===\n');

// Check 1: Required fields
const required = schema.required;
let requiredOk = true;
for (const field of required) {
  const hasField = field in task;
  console.log(\`✓ Required field '\${field}': \${hasField}\`);
  if (!hasField) requiredOk = false;
}

console.log('');

// Check 2: Field count (should be exactly 3)
const keys = Object.keys(task);
console.log(\`✓ Exact field count: \${keys.length} (expected 3)\`);
console.log(\`  Fields: \${keys.join(', ')}\`);

console.log('');

// Check 3: Validate each field
console.log('=== FIELD VALIDATION ===\n');

// title
console.log(\`title: '\${task.title}'\`);
console.log(\`  - type: string ✓\`);
console.log(\`  - minLength 1: \${task.title.length >= 1 ? '✓' : '✗'}\`);

// priority
console.log(\`priority: '\${task.priority}'\`);
const validPriorities = ['low', 'medium', 'high', 'critical'];
const priorityValid = validPriorities.includes(task.priority);
console.log(\`  - enum check [\${validPriorities.join(', ')}]: \${priorityValid ? '✓' : '✗'}\`);

// due_date
console.log(\`due_date: '\${task.due_date}'\`);
const datePattern = /^[0-9]{4}-[0-9]{2}-[0-9]{2}$/;
const dateValid = datePattern.test(task.due_date);
console.log(\`  - pattern YYYY-MM-DD: \${dateValid ? '✓' : '✗'}\`);

console.log('');

// Check 4: No additional properties
console.log('=== ADDITIONAL PROPERTIES CHECK ===\n');
const schemaProps = Object.keys(schema.properties);
for (const key of keys) {
  const allowed = schemaProps.includes(key);
  console.log(\`\${key}: \${allowed ? '✓ allowed' : '✗ not in schema'}\`);
}

console.log('');

// Check 5: Verify optional fields NOT included
console.log('=== OPTIONAL FIELDS (should NOT be present) ===\n');
console.log(\`tags: \${'tags' in task ? '✗ PRESENT (should not be)' : '✓ not present (correct)'}\`);
console.log(\`assignee: \${'assignee' in task ? '✗ PRESENT (should not be)' : '✓ not present (correct)'}\`);

console.log('');

// Final verdict
const allChecks = [
  requiredOk,
  keys.length === 3,
  task.title.length >= 1,
  validPriorities.includes(task.priority),
  dateValid,
  !('tags' in task),
  !('assignee' in task)
];

const allPassed = allChecks.every(c => c);
console.log(\`=== FINAL VERDICT ===\n\${allPassed ? '✓ ALL CHECKS PASSED' : '✗ SOME CHECKS FAILED'}\`);
"
